    VD: { kanton: 'VD', erlassName: "Tarif des honoraires dus aux notaires pour des opérations ministérielles (TNo)", erlassNr: "BLV 178.11.2", artikel: "Art. 23 TNo (BLV 178.11.2)", stand: "01.03.2016", verifiziert: R, quelleUrl: "https://prestations.vd.ch/pub/blv-publication/actes/consolide/178.11.2?id=26c09c57-9d81-4ec3-a442-e33bc904027b", hinweis: "Art. 23 TNo (autres servitudes, notamment droits d'habitation et d'usufruit): Ermessensrahmen CHF 100-2'000 fuer Konstitution und Modifikation. Achtung Abgrenzung: Baurecht/droit de superficie laeuft ueber Art. 22 (% Barème Art. 14), Wegrechte/Leitungsdienstbarkeiten ggf. ebenfal", regel: { typ: 'rahmen', vonChf: 100, bisChf: 2000 } },
