    ZH: { kanton: 'ZH', erlassName: "Notariatsgebührenverordnung (NotGebV)", erlassNr: "LS 243", artikel: "NotGebV LS 243, Anhang Ziff. 1.4.1.1 (Dienstbarkeiten/Grundlasten, Begruendung und Ausdehnung); Aenderung Ziff. 1.4.1.2", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.zh.ch/de/politik-staat/gesetze-beschluesse/gesetzessammlung/zhlex-ls/erlass-243-2009_03_09-2009_07_01-123.html", hinweis: "1‰ vom Wert der Gegenleistung, mind. 150; bei wiederkehrenden Leistungen Kapitalisierungsdeckel = 20-facher Jahreswert (z.B. Nutzniessung/Wohnrecht). BEIM FEHLEN EINER GEGENLEISTUNG Rahmen 150-1000 (regelTyp rahmen); reine AENDERUNG (Ziff. 1.4.1.2) ebenfalls 150-1000. Grundbuch-E", regel: { typ: 'promille', promille: 1, minChf: 150 } },
