    JU: { kanton: 'JU', erlassName: "Décret fixant les émoluments des notaires", erlassNr: "RSJU 189.61", artikel: "RSJU 189.61 Art. 10 al. 1", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1", hinweis: "Cedule hypothecaire / contrat de gage immobilier: degressive Staffel nach somme du gage, Mindestgebuehr 100 CHF, keine Hoechstgrenze. Korrigiert: bisher faelschlich Art. 9 al. 1 / Aufwand; richtig Art. 10.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 0, abChf: 0, prozent: 0.5, minChf: 100 }, { bisChf: 300000, sockelChf: 500, abChf: 100000, prozent: 0.35, minChf: 100 }, { bisChf: 500000, sockelChf: 1200, abChf: 300000, prozent: 0.3, minChf: 100 }, { bisChf: 1000000, sockelChf: 1800, abChf: 500000, prozent: 0.2, minChf: 100 }, { bisChf: Infinity, sockelChf: 2800, abChf: 1000000, prozent: 0.1, minChf: 100 }] } },
