    OW: { kanton: 'OW', erlassName: "Verordnung über die Beurkundungsgebühren", erlassNr: "GDB 210.32", artikel: "Art. 10 Ziff. 23 (ZGB 799)", stand: "2012-04-01", verifiziert: R, quelleUrl: "https://gdb.ow.ch/app/de/texts_of_law/210.32", hinweis: "Errichtung/Umwandlung eines Grundpfandes (Schuldbrief): 1,5%o bis 300k, +1%o bis 600k, +0,5%o ueber 600k, mind. 400. Bei 1M = 950 (nicht 1900). Pfandrechtserneuerung/Aufteilung/Verlegung: -1/4; andere Aenderungen max. die Haelfte.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 300000, sockelChf: 0, abChf: 0, prozent: 0.15, minChf: 400 }, { bisChf: 600000, sockelChf: 450, abChf: 300000, prozent: 0.1, minChf: 400 }, { bisChf: Infinity, sockelChf: 750, abChf: 600000, prozent: 0.05, minChf: 400 }] } },
