    GR: { kanton: 'GR', erlassName: "Verordnung über die Notariatsgebühren (NotGebV)", erlassNr: "BR 210.370", artikel: "Art. 17 Abs. 1 lit. a NotGebV (BR 210.370)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.gr-lex.gr.ch/api/de/versions/3348/pdf_file", hinweis: "Errichtung AG (auch Kommanditaktiengesellschaft): Sockel Fr. 1'000 + 1 Promille vom Aktienkapital ueber 200'000; KEIN Maximum genannt. Bei 1M = 1'000 + 800 = 1'800 (NICHT 1'000). Sacheinlage = wie Art. 15/16 lit. a. Beleg: gr-lex.gr.ch/app/de/texts_of_law/210.370", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 1000, abChf: 0, prozent: 0, minChf: 1000 }, { bisChf: Infinity, sockelChf: 1000, abChf: 200000, prozent: 0.1, minChf: 1000 }] } },
    JU: { kanton: 'JU', erlassName: "Décret concernant les émoluments des notaires du 6 décembre 1978", erlassNr: "RSJU 189.61", artikel: "RSJU 189.61 Art. 16 al. 1", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1", hinweis: "Art. 16 al. 1: Sockel CHF 300 fuer die ersten 100'000 Gesellschaftskapital (erstes Band promille=0 entspricht Pauschale 300, abgebildet via sockelChf), dann 2 Promille fuer die naechsten 400'000 (100'001-500'000), 1,5 Promille ueber 500'000. CHF 300 ist nur der Sockel; bei hoeher", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 300, abChf: 0, prozent: 0, minChf: 300 }, { bisChf: 500000, sockelChf: 300, abChf: 100000, prozent: 0.2, minChf: 300 }, { bisChf: Infinity, sockelChf: 1100, abChf: 500000, prozent: 0.15, minChf: 300 }] } },
    LU: { kanton: 'LU', erlassName: "Verordnung über die Beurkundungsgebühren (BeurkGebV)", erlassNr: "SRL 258", artikel: "BeurkGebV § 37 Abs. 1 (SRL 258)", stand: "2022-01-01", verifiziert: R, quelleUrl: "https://srl.lu.ch/api/de/versions/3870/pdf_file_with_annexes", hinweis: "§ 37 Abs. 1 (Gründung AG/Kommandit-AG): marginale degressive Staffel vom Grundkapital 3‰ bis 500k, 2,5‰ bis 1 Mio., 2‰ bis 2 Mio., 1,5‰ bis 5 Mio., 0,5‰ bis 10 Mio., über 10 Mio. keine Gebühr; mindestens Fr. 1000.–, höchstens Fr. 11'750.–. Bisherige Kodierung als flacher Rahmen 1", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 500000, sockelChf: 0, abChf: 0, prozent: 0.3, minChf: 1000, maxChf: 11750 }, { bisChf: 1000000, sockelChf: 1500, abChf: 500000, prozent: 0.25, minChf: 1000, maxChf: 11750 }, { bisChf: 2000000, sockelChf: 2750, abChf: 1000000, prozent: 0.2, minChf: 1000, maxChf: 11750 }, { bisChf: 5000000, sockelChf: 4750, abChf: 2000000, prozent: 0.15, minChf: 1000, maxChf: 11750 }, { bisChf: 10000000, sockelChf: 9250, abChf: 5000000, prozent: 0.05, minChf: 1000, maxChf: 11750 }, { bisChf: Infinity, sockelChf: 11750, abChf: 10000000, prozent: 0, minChf: 1000, maxChf: 11750 }] } },
    NE: { kanton: 'NE', erlassName: "Arrêté fixant le tarif des émoluments des notaires", erlassNr: "RSN 166.31", artikel: "Tarif notaires RSN 166.31 Art. 14 ch. 81 lit. A ch. 1 (Constitution SA)", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsn.ne.ch/DATA/program/books/RSN2015/20154/htm/16631.htm", hinweis: "AG-Gruendung: Grundgebuehr (proces-verbal) 500 fr. PLUS degressive marginale Promille auf das Aktienkapital (5 Promille bis 100k, 2 bis 500k, 1 bis 1M, 0,5 darueber), Hoechstgebuehr 11800 fr.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 500, abChf: 0, prozent: 0.5, maxChf: 11800 }, { bisChf: 500000, sockelChf: 1000, abChf: 100000, prozent: 0.2, maxChf: 11800 }, { bisChf: 1000000, sockelChf: 1800, abChf: 500000, prozent: 0.1, maxChf: 11800 }, { bisChf: Infinity, sockelChf: 2300, abChf: 1000000, prozent: 0.05, maxChf: 11800 }] } },
    NW: { kanton: 'NW', erlassName: "Verordnung über die Beurkundungsgebühren (Beurkundungsgebührenverordnung, BeurkGebV)", erlassNr: "268.12", artikel: "NG 268.12 § 36 Ziff. 1", stand: "01.01.2016", verifiziert: R, quelleUrl: "https://gesetze.nw.ch/app/de/texts_of_law/268.12", hinweis: "Definierter Tarif (NICHT Aufwand/Vereinbarung): Grundgebuehr Fr. 1'000 bis Aktienkapital Fr. 200'000, danach marginal +3 Promille bis 500k, +2 Promille bis 1M, +1 Promille bis 5M, +0.5 Promille darueber. Gilt auch fuer Kommanditaktiengesellschaft (Art. 764 Abs. 2 OR). Bei Aktienk", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 500000, sockelChf: 1000, abChf: 200000, prozent: 0.3, minChf: 1000 }, { bisChf: 1000000, sockelChf: 1900, abChf: 500000, prozent: 0.2, minChf: 1000 }, { bisChf: 5000000, sockelChf: 2900, abChf: 1000000, prozent: 0.1, minChf: 1000 }, { bisChf: Infinity, sockelChf: 6900, abChf: 5000000, prozent: 0.05, minChf: 1000 }] } },
