    ZH: { kanton: 'ZH', erlassName: "Notariatsgebührenverordnung (NotGebV)", erlassNr: "LS 243", artikel: "NotGebV LS 243, Anhang Ziff. 4.4.3.1 (Gruendung oder Kapitalerhoehung einer AG oder GmbH)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.zh.ch/de/politik-staat/gesetze-beschluesse/gesetzessammlung/zhlex-ls/erlass-243-2009_03_09-2009_07_01-123.html", hinweis: "1‰ vom Kapital. Rahmen-Hoechstbetraege per 1.1.2024 gesenkt: uebrige Gesellschaften 500-4000 (hier kodiert), groessere Unternehmen Art. 727 Abs. 1 Ziff. 2/3 OR 500-8000, Publikumsgesellschaften Art. 727 Abs. 1 Ziff. 1 OR 500-12000. Geschaefte geringerer Bedeutung: Finanzdirektion", regel: { typ: 'promille', promille: 1, minChf: 500, maxChf: 4000 } },
