    VD: { kanton: 'VD', erlassName: "Tarif des honoraires dus aux notaires pour des opérations ministérielles (TNo)", erlassNr: "BLV 178.11.2", artikel: "Art. 26 al.1 u. al.2 TNo (BLV 178.11.2)", stand: "01.03.2016", verifiziert: R, quelleUrl: "https://prestations.vd.ch/pub/blv-publication/actes/consolide/178.11.2?id=26c09c57-9d81-4ec3-a442-e33bc904027b", hinweis: "Art. 26 TNo erfasst ausdruecklich die Sàrl/GmbH: Grundgebuehr-Rahmen CHF 200-2'000 (al.1) PLUS Kapitalstaffel auf Stammkapital bei Gruendung (al.2, 3‰ bis 0,25‰). sockelChf=200 = Untergrenze Rahmen, Ermessen bis CHF 2'000. Stammkapital GmbH idR CHF 20'000.", regel: { typ: 'staffel_sockel_prozent', aufschlagBisChf: 1800, baender: [{ bisChf: 100000, sockelChf: 200, abChf: 0, prozent: 0.3, minChf: 200 }, { bisChf: 200000, sockelChf: 500, abChf: 100000, prozent: 0.2, minChf: 200 }, { bisChf: 500000, sockelChf: 700, abChf: 200000, prozent: 0.15, minChf: 200 }, { bisChf: 10000000, sockelChf: 1150, abChf: 500000, prozent: 0.1, minChf: 200 }, { bisChf: 20000000, sockelChf: 10650, abChf: 10000000, prozent: 0.05, minChf: 200 }, { bisChf: Infinity, sockelChf: 15650, abChf: 20000000, prozent: 0.025, minChf: 200 }] } },
    VS: { kanton: 'VS', erlassName: "Tarif des émoluments des notaires", erlassNr: "RS 178.104", artikel: "Art. 13 al. 1 i.V.m. Art. 11 let. e ch. 4 (acte constitutif Sarl, art. 777 CO); Bemessung Art. 12 al. 1, RS 178.104", stand: "01.01.2011", verifiziert: R, quelleUrl: "https://lex.vs.ch/app/fr/texts_of_law/178.104", hinweis: "Acte constitutif de la Sarl ist proportionaler Akt (Art. 11 let. e ch. 4) -> degressive Staffel Art. 13 al. 1 auf das Stammkapital (Art. 12 al. 1). KORREKTUR: nicht 'nach Vereinbarung/Aufwand'.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 200, abChf: 5000, prozent: 0.5, minChf: 200 }, { bisChf: 500000, sockelChf: 1175, abChf: 200000, prozent: 0.4, minChf: 200 }, { bisChf: 1000000, sockelChf: 2375, abChf: 500000, prozent: 0.3, minChf: 200 }, { bisChf: 10000000, sockelChf: 3875, abChf: 1000000, prozent: 0.2, minChf: 200 }, { bisChf: Infinity, sockelChf: 21875, abChf: 10000000, prozent: 0.1, minChf: 200 }] } },
    ZG: { kanton: 'ZG', erlassName: "Kantonsratsbeschluss über die Gebühren in Verwaltungs- und Zivilsachen (Verwaltungsgebührentarif)", erlassNr: "641.1", artikel: "BGS 641.1 § 9 Abs. 1 Nr. 90", stand: "2026-06-16", verifiziert: R, quelleUrl: "https://bgs.zg.ch/app/de/texts_of_law/641.1", hinweis: "Nr. 90 'Gruendungen, Beschluesse und Feststellungen im Gesellschaftsrecht sowie nach Fusionsgesetz: 400 bis 15000'. Gebuehrenrahmen.", regel: { typ: 'rahmen', vonChf: 400, bisChf: 15000 } },
    ZH: { kanton: 'ZH', erlassName: "Notariatsgebührenverordnung (NotGebV)", erlassNr: "LS 243", artikel: "NotGebV LS 243, Anhang Ziff. 4.4.3.1 (Gruendung oder Kapitalerhoehung einer AG oder GmbH)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.zh.ch/de/politik-staat/gesetze-beschluesse/gesetzessammlung/zhlex-ls/erlass-243-2009_03_09-2009_07_01-123.html", hinweis: "1‰ vom Kapital. GmbH faellt regelmaessig unter 'uebrige Gesellschaften' (Rahmen 500-4000, per 1.1.2024 von 500-5000 gesenkt). Groessere/Publikumsgesellschaften analog 500-8000 bzw. 500-12000. MwSt nach § 2 zusaetzlich.", regel: { typ: 'promille', promille: 1, minChf: 500, maxChf: 4000 } },
