    AI: { kanton: 'AI', erlassName: "Gebührentarif (GebT)", erlassNr: "GS 172.513", artikel: "Art. 14 Abs. 3 Ziff. 7 GebT (GS 172.513)", stand: "2026-01-01", verifiziert: R, quelleUrl: "https://ai.clex.ch/app/de/texts_of_law/172.513", hinweis: "Errichtung einer Stiftung (Art. 81 ZGB) 400-4'000.", regel: { typ: 'rahmen', vonChf: 400, bisChf: 4000 } },
    AR: { kanton: 'AR', erlassName: "Gesetz über die Gebühren der Gemeinden (Gebührentarif für die Gemeinden)", erlassNr: "bGS 153.2", artikel: "Art. 12 Ziff. 5.1 bGS 153.2", stand: "1.1.2018", verifiziert: R, quelleUrl: "https://ar.clex.ch/api/de/versions/1203/pdf_file", hinweis: "Errichtung einer Stiftung oder Abaenderung (Art. 81 ZGB): 1‰ des Stiftungskapitals im Rahmen von Fr. 100–2000. (Korrektur: flacher Promillesatz 1‰ mit Rahmen, nicht reiner Rahmen 100–2000.)", regel: { typ: 'promille', promille: 1, minChf: 100, maxChf: 2000 } },
