    BE: { kanton: 'BE', erlassName: "Verordnung über die Gebühren der Notare (GebVN)", erlassNr: "BSG 169.81", artikel: "Art. 1a Abs. 2 i.V.m. Art. 30 Abs. 1 bzw. Art. 4 Abs. 3, Art. 3a Abs. 1 GebVN (BSG 169.81)", stand: "01.03.2022", verifiziert: R, quelleUrl: "https://www.belex.sites.be.ch/app/de/texts_of_law/169.81", hinweis: "KORREKTUR: Schuldanerkennung ist in GebVN nicht eigens tarifiert und hat regelmaessig keinen Anhang-1-Geschaeftswert. Einschlaegig: Art. 1a Abs. 2 (Geschaeft ohne Geschaeftswert -> Zeitaufwand) i.V.m. Art. 30 Abs. 1 (nicht erforderliche Beurkundung, mind. 300) bzw. Art. 4 Abs. 3", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand, Stundenansatz CHF 400. KORREKTUR: Schuldanerkennung ist in GebVN nicht eigens tarifiert und hat regelmaessig keinen Anhang-1-Geschaeftswert. Einschlaegig: Art. 1a Abs. 2 (Geschaeft ohne Geschaeftswert -" } },
    BS: { kanton: 'BS', erlassName: "Verordnung über den Notariatstarif", erlassNr: "SG 292.400", artikel: "§ 11 Ziff. 42 (Auffangtatbestand); ggf. Ziff. 36a (Unterwerfungserklaerung), Ziff. 28 (grundpfandgesichert) Notariatstarif SG 292.400", stand: "1.7.2016", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.bs.ch/app/de/texts_of_law/292.400", hinweis: "Reine Schuldanerkennung beduerfte keiner Beurkundung; falls dennoch verlangt, gilt Ziff. 42 'gemaess Zeitaufwand und Bedeutung, mindestens CHF 200'. Mit Unterwerfungserklaerung (vollstreckbare oeffentliche Urkunde Art. 347 ZPO) gilt Ziff. 36a: separat CHF 400-1000, im Rahmen eine", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand. Reine Schuldanerkennung beduerfte keiner Beurkundung; falls dennoch verlangt, gilt Ziff. 42 'gemaess Zeitaufwand und Bedeutung, mindestens CHF 200'. Mit Unterwerfungserklaerung (vollstreckbare oeffentli" } },
    FR: { kanton: 'FR', erlassName: "Tarif des émoluments des notaires", erlassNr: "RSF 261.16", artikel: "Art. 5 ch. 12", stand: "7.10.1986", verifiziert: R, quelleUrl: "https://bdlf.fr.ch/api/fr/versions/8428/pdf_file", hinweis: "KORRIGIERT: Reconnaissance de dette (Schuldanerkennung) ist nicht eigens genannt und fällt unter Auffang Art. 5 ch. 12 'Actes non énumérés' = Rahmen 50-1500 (Ermessen), KEIN proportionaler/Formel-Wert.", regel: { typ: 'rahmen', vonChf: 50, bisChf: 1500 } },
    GE: { kanton: 'GE', erlassName: "Règlement sur les émoluments des notaires (REmNot)", erlassNr: "RSG E 6 05.03", artikel: "Art. 27 REmNot (RSG E 6 05.03)", stand: "2015-04-30", verifiziert: R, quelleUrl: "https://silgeneve.ch/legis/program/books/rsg/htm/rsg_e6_05p03.htm", hinweis: "Reconnaissance de dette ist nicht translativ → Art. 10 war falsch. Keine spezifische REmNot-Norm; als 'acte authentique non prevu' nach Art. 27 (100-2000 francs). Hinweis: Enthaelt die Urkunde eine vollstreckbare Klausel (titre executoire), gilt zusaetzlich/alternativ Art. 26A (w", regel: { typ: 'rahmen', vonChf: 100, bisChf: 2000 } },
    GL: { kanton: 'GL', erlassName: "Verordnung über Beurkundung und Beglaubigung mit Gebührentarif", erlassNr: "GS III B/3/2", artikel: "Art. A1-3 (Anhang) GS III B/3/2", stand: "1.1.2009", verifiziert: R, quelleUrl: "https://gesetze.gl.ch/app/de/texts_of_law/III%20B%2F3%2F2", hinweis: "Kein eigener Tatbestand (A1-2 nur Buergschaft); Auffangrahmen A1-3: 100-1000 Fr.", regel: { typ: 'rahmen', vonChf: 100, bisChf: 1000 } },
    GR: { kanton: 'GR', erlassName: "Verordnung über die Notariatsgebühren (NotGebV)", erlassNr: "BR 210.370", artikel: "Art. 19a Abs. 1 lit. a NotGebV; sonst Art. 7 (BR 210.370)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.gr-lex.gr.ch/api/de/versions/3348/pdf_file", hinweis: "Als vollstreckbare oeffentliche Urkunde (Schuldanerkennung mit Vollstreckbarkeitsklausel): Errichtung fix Fr. 200 (Art. 19a Abs. 1 lit. a). Zustellung durch errichtende Notariatsperson Fr. 100 (lit. b), durch andere Fr. 100-200 (lit. c). Ohne Vollstreckbarkeit ohne eigene Positio", regel: { typ: 'fix', chf: 200 } },
    JU: { kanton: 'JU', erlassName: "Décret fixant les émoluments des notaires", erlassNr: "RSJU 189.61", artikel: "RSJU 189.61 Art. 6 al. 1 (i.V.m. Art. 3)", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1", hinweis: "Reine Schuldanerkennung hat keine eigene Promille-Position; einschlaegig Art. 6 al. 1 (activite accessoire, nach Bedeutung/Verantwortung/Zeit) bzw. Art. 3 (analoge Position). Kein fester Stundensatz im Erlass. Korrigiert: Artikelzitat Art. 9 al. 1 war falsch.", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand. Reine Schuldanerkennung hat keine eigene Promille-Position; einschlaegig Art. 6 al. 1 (activite accessoire, nach Bedeutung/Verantwortung/Zeit) bzw. Art. 3 (analoge Position). Kein fester Stundensatz im" } },
