    SG: { kanton: 'SG', erlassName: "Verordnung über die Gebühren für Amtshandlungen der Grundbuchämter und für die Durchführung von Grundstückschätzungen (GB-GebV) — für grundstücksbezogene Beurkundungen; ergänzt durch Gebührentarif für die Kantons- und Gemeindeverwaltung (GebT), Abschnitt III «Beurkundungen und Beglaubigungen», für die übrigen öffentlichen Beurkundungen", erlassNr: "914.5 (GB-GebV); 821.5 (GebT)", artikel: "GB-GebV (sGS 914.5) Art. 10 Nr. 21.01 (grundpfandgesichert) i.V.m. Art. 5 Abs. 2", stand: "1.6.2020", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.sg.ch/api/de/versions/2935/pdf_file_with_annexes", hinweis: "Grundpfandgesicherte Schuldanerkennung folgt Nr. 21.01: 1 Promille der Pfandsumme, Rahmen 100-2000 (bei 1 Mio. = 1000, nicht 2000); einfacher Satz Art. 5 Abs. 2, mit Eintrag verdoppelt. REINE (nicht grundpfandbezogene) Schuldanerkennung: NICHT Nr. 20.01, sondern Auffangtarif (z.B", regel: { typ: 'promille', promille: 1, minChf: 100, maxChf: 2000 } },
