    SZ: { kanton: 'SZ', erlassName: "Gebührentarif für Notare und Grundbuchverwalter sowie freiberufliche Urkundspersonen", erlassNr: "SRSZ 213.512", artikel: "§ 5 Abs. 1 Nr. 3 (ggf. Nr. 13)", stand: "1.2.2021", verifiziert: R, quelleUrl: "https://www.sz.ch/public/upload/assets/7361/213_512.pdf", hinweis: "KORREKTUR: Eine reine Schuldanerkennung ist weder Handänderung noch Begründung/Änderung eines Rechts an Grundstücken → kein Promille-Tarif. Aufnahme als Geschäft im Urkundenprotokoll nach Nr. 3 = Fr. 6-20 je Seite (Rahmen pro Seite). Übersteigt der Aufwand 2 Std., greift der Auff", regel: { typ: 'rahmen', vonChf: 6, bisChf: 20 } },
    TG: { kanton: 'TG', erlassName: "Gesetz über die Gebühren und Gemengsteuern der Grundbuchämter und Notariate (GGG)", erlassNr: "RB 632.1", artikel: "§ 16 GGG (RB 632.1)", stand: "2026 (konsolidiert)", verifiziert: R, quelleUrl: "https://www.rechtsbuch.tg.ch/api/de/texts_of_law/632.1", hinweis: "KORREKTUR (Drittprüfung): § 16 Rahmen Fr. 200–10'000 pro Geschäft nach Aufwand/Bedeutung; nicht frei vereinbar.", regel: { typ: 'rahmen', vonChf: 200, bisChf: 10000 } },
