    UR: { kanton: 'UR', erlassName: "Notariatstarif der Urner Notarinnen und Notare (Verbands-Konventionaltarif)", erlassNr: "urilaw.ch (RB 9.2311)", artikel: "Notariatstarif UR Ziff. 4 (Stundenansatz); Ziff. 5.1 abschliessend", stand: "17.3.2015", verifiziert: R, quelleUrl: "https://www.urilaw.ch/fileadmin/user_upload/documents/Notariatstarif-Uri.pdf", hinweis: "KORREKTUR: Reine Schuldanerkennung ist in abschliessender Tarif-A-Liste Ziff. 5.1 lit. a-g NICHT genannt und in Ziff. 7 nicht aufgefuehrt. Mangels Tarifposition Abrechnung nach Stundenansatz Ziff. 4 (CHF 250-350/Std, Mittelwert 300). Ist die Schuldanerkennung grundpfandbezogen, g", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand, Stundenansatz CHF 300. KORREKTUR: Reine Schuldanerkennung ist in abschliessender Tarif-A-Liste Ziff. 5.1 lit. a-g NICHT genannt und in Ziff. 7 nicht aufgefuehrt. Mangels Tarifposition Abrechnung nach St" } },
    VD: { kanton: 'VD', erlassName: "Tarif des honoraires dus aux notaires pour des opérations ministérielles (TNo)", erlassNr: "BLV 178.11.2", artikel: "Art. 30 TNo (BLV 178.11.2) bzw. Art. 2 TNo i.V.m. Art. 118 LNo (nicht tarifiert)", stand: "01.01.2005", verifiziert: R, quelleUrl: "https://prestations.vd.ch/pub/blv-publication/actes/consolide/178.11.2?id=26c09c57-9d81-4ec3-a442-e33bc904027b", regel: { typ: 'rahmen', vonChf: 20, bisChf: 500 } },
    ZH: { kanton: 'ZH', erlassName: "Notariatsgebührenverordnung (NotGebV)", erlassNr: "LS 243", artikel: "NotGebV LS 243, Anhang Ziff. 4.6 (Oeffentliche Beurkundung von Willenserklaerungen, in Ziff. 4 nicht genannt)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.zh.ch/de/politik-staat/gesetze-beschluesse/gesetzessammlung/zhlex-ls/erlass-243-2009_03_09-2009_07_01-123.html", hinweis: "KORREKTUR: Schuldanerkennung ist keine Eigentumsuebertragung (Ziff. 1.1.1 falsch). Als Willenserklaerung ohne eigene Ziffer faellt sie unter die Auffangnorm Ziff. 4.6: 1‰ von der Gegenleistung bzw. vom betroffenen Vermoegenswert, im Rahmen 200-15000 (Cap 15000). MwSt nach § 2 zus", regel: { typ: 'promille', promille: 1, minChf: 200, maxChf: 15000 } },
