    BS: { kanton: 'BS', erlassName: "Verordnung über den Notariatstarif", erlassNr: "SG 292.400", artikel: "Verordnung über den Notariatstarif (SG 292.400) § 11 Abs. 1 Ziff. 33 lit. f", stand: "1. Juli 2016", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.bs.ch/app/de/texts_of_law/292.400", hinweis: "Beurkundungspflichtige Statutenänderung AG/GmbH ohne Kapitalveränderung (Art. 647 OR) fällt unter Ziff. 33 lit. f 'Andere Generalversammlungsprotokolle: CHF 500 bis CHF 2'000' (Rahmentaxe). Betrifft die Statutenänderung eine Kapitalveränderung, gelten stattdessen Ziff. 33 lit. c", regel: { typ: 'rahmen', vonChf: 500, bisChf: 2000 } },
